import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,a as t}from"./app-1ddbbf08.js";const n="/assets/images/vasvari/maven.webp",l={},o=t('<h1 id="maven-projektkezeles" tabindex="-1"><a class="header-anchor" href="#maven-projektkezeles" aria-hidden="true">#</a> Maven projektkezelés</h1><p>Egy alkalmazás fejlesztésekor általában nem érdemes minden programrészt teljesen saját magunknak létrehozni. Sokszor találhatunk olyan jól bevált megoldásokat más fejlesztők által készített könyvtárak vagy keretrendszerek formájában, amelyek segíthetnek a projektünk során. Ezeket az eszközöket általában függőségekként, vagyis az alkalmazásunk függőségeiként kezeljük, és beépítjük őket a projektünkbe. Például egy Java projekt esetében ezek a függőségek gyakran <code>JAR</code> fájlok formájában vannak jelen.</p><p>Hosszú időkkel ezelőtt, egy sötétebb korszakban, amikor egy új projektbe kapcsolódtunk be vagy mi magunk indítottunk egy újat, a függőségeket saját magunknak kellett manuálisan letölteni és beállítani az <strong>IDE</strong> alkalmazásunkban. Ez rengeteg bosszúságot okozhatott. Egykoron az <strong>Apache Ant</strong> eszköz szolgált a konfigurációs problémák megoldására, de ma már elavultnak számít a bonyolult scriptnyelve miatt. Ráadásul <strong>Ant</strong> használata során is saját magunknak kellett letölteni a függőségeket, így gyakran előfordulhatott, hogy kollégáink különböző verziójú függőségekkel dolgoztak, ami pedig súlyos következményekkel járhatott.</p><p>Jelenleg az Apache Maven eszközt alkalmazzuk projektjeink létrehozásához és kezeléséhez. Maven használatával a projekt összes szükséges információját egyszerűen egy <code>XML</code> fájlban határozhatjuk meg. A különböző függőségek kezelése sem jelent többé problémát, mivel a Maven automatikusan letölti őket egy <strong>repositoryból</strong> az <code>XML</code> fájlban megadott információk alapján.</p><p>A <code>Maven Central Repository</code> egy hatalmas gyűjteményt kínál különböző projektekhez, de emellett más <code>repository</code>-k is elérhetők, például a gyártók által létrehozottak, illetve akár saját <code>repository</code>-t is hozhatunk létre.</p><h2 id="maven-tortenete" tabindex="-1"><a class="header-anchor" href="#maven-tortenete" aria-hidden="true">#</a> Maven története</h2><p>Az Apache Maven projekt 2002-ben indult, és a fejlesztés során az alapvető cél az volt, hogy egy nyílt forráskódú, szabványos projektkezelő eszközt hozzanak létre a Java közösség számára. A Maven azóta nagy népszerűségnek örvend a szoftvertervezés és -fejlesztés területén. A projektet aktívan karbantartja az Apache Software Foundation, és folyamatosan fejlesztik, hogy a fejlesztők igényeinek megfeleljen.</p><h3 id="maven-alapelvei" tabindex="-1"><a class="header-anchor" href="#maven-alapelvei" aria-hidden="true">#</a> Maven alapelvei</h3><p>A Maven tervezésekor alapelvek mentén haladtak, amelyek meghatározzák az eszköz működését és tervezését. Megalkotja a projekt struktúráját és fájlrendezését melynek köszönhetően a fejlesztőknek nem kell túl sok időt tölteniük a konfigurációval, mivel alapértelmezett beállításokat használ, amelyeket könnyen felül lehet írni, ha szükséges. Lehetővé teszi a projekt függőségeinek deklaratív megadását egy <code>pom.xml</code> (<strong>Project Object Model</strong>) fájlban. Ez a fájl tartalmazza a projekt leírását, a függőségeket, a build beállításokat és a pluginok konfigurációját. Továbbá támogatja a teljes projektéletciklust, beleértve a projekt generálását, fordítását, tesztelését, csomagolását, telepítését és más feladatokat.</p><figure><img src="'+n+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="maven-fo-funkcioi" tabindex="-1"><a class="header-anchor" href="#maven-fo-funkcioi" aria-hidden="true">#</a> Maven fő funkciói</h3><ol><li><p><strong>Build menedzsment:</strong> Maven kezeli a projekt build folyamatát, amely magában foglalja a forráskód fordítását, a tesztelést és a csomagolást. A build folyamatot XML-alapú konfigurációs fájl, a <code>pom.xml</code> vezérli.</p></li><li><p><strong>Függőségek kezelése:</strong> A Maven lehetővé teszi a külső függőségek egyszerű deklarálását és kezelését. A függőségeket központi repository-kből letölti, így nem kell manuálisan letölteni és hozzáadni őket a projekthez.</p></li><li><p><strong>Projekt generálás:</strong> Maven képes új projektstruktúrák generálására, például egy alapvető Java alkalmazást vagy webalkalmazást. Ez segít a projekt kezdeti beállításában.</p></li><li><p><strong>Tesztelés és dokumentáció generálás:</strong> Maven automatizálja a projekt tesztelési folyamatát és lehetővé teszi a dokumentáció generálását is.</p></li><li><p><strong>Pluginok támogatása:</strong> Maven pluginok segítségével bővíthető és testreszabható. Számos beépített plugin áll rendelkezésre, például a Java Compiler plugin, a JUnit tesztelés plugin és a site generálás plugin.</p></li></ol><h3 id="az-alkalmazasa-es-az-iparagban-betoltott-szerepe" tabindex="-1"><a class="header-anchor" href="#az-alkalmazasa-es-az-iparagban-betoltott-szerepe" aria-hidden="true">#</a> Az alkalmazása és az iparágban betöltött szerepe</h3><p>Az Apache Maven alkalmazása sokszínű, és számos iparágban és projekt típusban használják. Néhány példa:</p><ol><li><p><strong>Java fejlesztés:</strong> A Maven az egyik legelterjedtebb projektkezelő eszköz a Java közösségben. A Java projektek gyakran használják a Maven-t a build folyamat automatizálásához, a függőségek kezeléséhez és a projekt struktúrájának egységesítéséhez.</p></li><li><p><strong>Webalkalmazások:</strong> A webalkalmazások fejlesztésekor a Maven hasznos lehet a projektstruktúra és a függőségek kezelésében. A Maven lehetővé teszi a Java EE alkalmazások könnyű konfigurációját is.</p></li><li><p><strong>Open Source projektek:</strong> Az open source projektek és könyvtárak fejlesztői gyakran használnak Maven-t a könnyű hozzáférhetőség és a függőségek dokumentálásának lehetősége miatt.</p></li><li><p><strong>CI/CD (Continuous Integration/Continuous Deployment) rendszerek:</strong> A Maven integrálható különböző CI/CD rendszerekkel, például a Jenkins-szel, a Travis CI-vel vagy a CircleCI-vel, így automatizálható a projekt fordítása, tesztelése és elterjesztése.</p></li><li><p><strong>Keretrendszerek és platformok:</strong> Néhány keretrendszer, például a Spring Framework, szorosan együttműködik a Maven-nel, hogy egyszerűsítse a projektfejlesztést.</p></li></ol><h2 id="pom-xml" tabindex="-1"><a class="header-anchor" href="#pom-xml" aria-hidden="true">#</a> <code>pom.xml</code></h2><p>Az Apache Maven projektkezelő rendszerben a <code>pom.xml</code> (<strong>Project Object Model</strong>) fájl a projekt konfigurációjának és leírásának központi eleme. Ebben a fájlban definiálják a projekt struktúráját, a függőségeket, a build folyamatot és a pluginokat. A <code>pom.xml</code> fájl alapvetően az Apache Maven működésének szívét képezi.</p><p>A <code>pom.xml</code> fájl feladatai és részei:</p><ol><li><p><strong>Projekt metaadatok:</strong> A fájl elején találhatóak olyan projektmetaadatok, mint a projekt neve, azonosítója, verziója, csomagnév (package name), fejlesztő neve és elérhetősége, valamint a projekt címe. Ezek az adatok azonosítják és leírják a projektet.</p></li><li><p><strong>Függőségek deklarációja:</strong> A <code>dependencies</code> vagy <code>dependencyManagement</code> szekciókban deklarálják a projekt külső függőségeit. Ezek a függőségek olyan könyvtárak vagy modulok, amelyekre a projekt épít, és amelyeket a Maven központi repository-ból automatikusan letölt.</p></li><li><p><strong>Build konfiguráció:</strong> A <code>build</code> szekció tartalmazza a projekt build folyamatának konfigurációját. Például itt találhatóak a forráskód helye, a fordítási beállítások, a tesztelési konfiguráció és a csomagolás beállításai.</p></li><li><p><strong>Pluginok konfigurációja:</strong> A <code>build/plugins</code> szekcióban találhatóak a Maven pluginok konfigurációi. Ezek a pluginok a build folyamat különböző szakaszaiban végzik el a különböző feladatokat, például a forráskód fordítását vagy a tesztelést.</p></li><li><p><strong>Verziókezelés:</strong> A <code>scm</code> szekcióban lehetőség van a projekt verziókezelési információinak <em>(például Git vagy Subversion repository URL)</em> megadására.</p></li></ol><p>A <code>pom.xml</code> fájl felépítése <strong>XML</strong> formátumú, és az Apache Maven követi a Maven Pluginok és az Apache Maven Build Lifecycle alapján. A fájl tartalmazhat további szekciókat és beállításokat is, amelyek a projekt specifikus igényeinek megfelelnek.</p><p>Az alábbi egy példa egy egyszerű <code>pom.xml</code> fájlra:</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token comment">&lt;!-- Kezdet a POM fájlnak --&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>project</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- A POM modell verziója --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>modelVersion</span><span class="token punctuation">&gt;</span></span>4.0.0<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>modelVersion</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- A projekt csoport azonosítója (általában a projekt szervezeti neve) --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>com.example<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- A projekt neve (artifact id) --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>my-project<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- A projekt verziója --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>1.0.0<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>

    <span class="token comment">&lt;!-- Függőségek szekciója, itt megadhatók a projekt függőségei --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependencies</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
            <span class="token comment">&lt;!-- A függőség csoport azonosítója --&gt;</span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.example<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
            <span class="token comment">&lt;!-- A függőség neve (artifact id) --&gt;</span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>library<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
            <span class="token comment">&lt;!-- A függőség verziója --&gt;</span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>1.0.0<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependencies</span><span class="token punctuation">&gt;</span></span>

    <span class="token comment">&lt;!-- A projekt felépítési konfigurációja (pl. forrásfájlok helye) --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>build</span><span class="token punctuation">&gt;</span></span>
        <span class="token comment">&lt;!-- A forrásfájlok elérési útja --&gt;</span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>sourceDirectory</span><span class="token punctuation">&gt;</span></span>src/main/java<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>sourceDirectory</span><span class="token punctuation">&gt;</span></span>
        <span class="token comment">&lt;!-- Build pluginek konfigurációja --&gt;</span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>plugins</span><span class="token punctuation">&gt;</span></span>
            <span class="token comment">&lt;!-- Ide kerülhetnek Maven pluginok konfigurációi --&gt;</span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>plugins</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>build</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>project</span><span class="token punctuation">&gt;</span></span>
<span class="token comment">&lt;!-- Vége a POM fájlnak --&gt;</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>Ez a példa bemutatja a legfontosabb elemeket, de a valóságban a <code>pom.xml</code> fájl sokkal részletesebb lehet a projekt igényeinek megfelelően. A fájl tartalmazza a projekt struktúrát, a függőségeket, a build folyamat beállításait és a további konfigurációs információkat a projekt hatékony kezeléséhez és build folyamatához.</p></div><p>A Maven-t konzolból lehet futtatni, miután a szükséges környezeti változókat beállítottuk a telepítés során az alábbi formában: <code>mvn &lt;utasítás1&gt; [&lt;utasítás2&gt;]</code>.</p><p>Maven projektjeink során build életciklus a következők:</p><ol><li><p><code>validate</code>: Ebben a fázisban ellenőrizzük a Maven projektet, hogy megfelelő-e formailag, és hogy rendelkezünk-e minden szükséges információval a build folyamathoz.</p></li><li><p><code>compile</code>: Ez a fázis a forráskód fordításáért felelős.</p></li><li><p><code>test</code>: A fordított kódot tesztekkel ellenőrizzük egy adott egységteszt keretrendszer segítségével. Fontos megjegyezni, hogy ezek a tesztek nem szükségesek a kész csomagoláshoz.</p></li><li><p><code>package</code>: Ebben a fázisban a fordított kódot valamilyen terjeszthető formátumba csomagoljuk, például jar-fájl formájában.</p></li><li><p><code>verify</code>: Integrációs teszteket futtatunk.</p></li><li><p><code>install</code>: Az elkészült csomagot a lokális repository-ba helyezzük el, hogy más projektben is felhasználható legyen függőségként.</p></li><li><p><code>deploy</code>: A build befejezéseként a végső csomagot a távoli repository-ba másoljuk, így megosztható lesz más fejlesztőkkel és projektekkel.</p></li></ol><p>További fontos fázisok közé tartozik a tisztítás (<code>clean</code>), ami törli a korábbi build során generált fájlokat.</p><p>Fontos megjegyezni, hogy egy adott életciklus fázis futtatásakor az előző fázisok is lefutnak. Például, ha <code>mvn package</code> parancsot adunk ki, akkor lefutnak a <code>validate</code>, <code>compile</code>, <code>test</code> és <code>package</code> fázisok is.</p><p>Hasznos gyakorlat lehet a build fázisokat a <code>clean</code> paranccsal kombinálni, mivel így töröljük a korábban generált fájlokat a friss fordítás előtt. Például: <code>mvn clean package</code>, vagy <code>mvn clean install</code>.</p><h2 id="osszefoglalo" tabindex="-1"><a class="header-anchor" href="#osszefoglalo" aria-hidden="true">#</a> Összefoglaló</h2><p>Az Apache Maven a modern szoftverfejlesztés terén, amely hatékony projektkezelést, build folyamat automatizálást és függőségkezelést kínál. A Maven a konvenciók és az egységes projektstruktúra alapján működik, és számos előnnyel jár a fejlesztők és a fejlesztői közösségek számára. Ugyanakkor fontos megjegyezni, hogy nem minden projekt vagy helyzet igényel a Maven használatát, és fontos az eszköz korlátainak és kritikáinak tudatában lenni. Az Apache Maven azonban továbbra is fontos szerepet tölt be a szoftverfejlesztésben, és aktívan hozzájárul a projektkezelés és a build folyamat hatékonyságához a fejlesztők számára.</p>`,31),k=[o];function i(p,r){return e(),s("div",null,k)}const d=a(l,[["render",i],["__file","lesson2.html.vue"]]);export{d as default};
